 22→const ParagraphCommentLayer = ({ containerRef, commentCounts, onParagraphClick }) => {
 23→    const [paragraphs, setParagraphs] = useState([]);
 24→    const [hoveredIndex, setHoveredIndex] = useState(null);
 25→    const [clickSeq, setClickSeq] = useState(0);
 26→    const listenersRef = useRef([]);
 27→    const leaveTimerRef = useRef(null);
 28→    const layerRef = useRef(null);
 29→    const clickedRef = useRef(false);
 30→    const prevActiveElRef = useRef(null);
 31→    const touchHandledRef = useRef(false);
 32→
 33→    const clearLeaveTimer = useCallback(() => {
 34→        if (leaveTimerRef.current) {
 35→            clearTimeout(leaveTimerRef.current);
 36→            leaveTimerRef.current = null;
 37→        }
 38→    }, []);
 39→
 40→    const scheduleLeave = useCallback((idx) => {
 41→        clearLeaveTimer();
 42→        leaveTimerRef.current = setTimeout(() => {
 43→            setHoveredIndex((prev) => prev === idx ? null : prev);
 44→        }, HOVER_LEAVE_DELAY_MS);
 45→    }, [clearLeaveTimer]);
 46→
 47→    const getParagraphIndex = useCallback((target) => {
 48→        const el = target?.closest?.('.editor-paragraph[data-paragraph-index]');
 49→        if (!el) return null;
 50→        return Number(el.getAttribute('data-paragraph-index'));
 51→    }, []);
 52→
 53→    const scanParagraphs = useCallback(() => {
 54→        const container = containerRef.current;
 55→        if (!container) return;
 56→
 57→        // Remove old hover listeners
 58→        listenersRef.current.forEach(({ el, enter, leave }) => {
 59→            el.removeEventListener('mouseenter', enter);
 60→            el.removeEventListener('mouseleave', leave);
 61→        });
 62→        listenersRef.current = [];
 63→
 64→        const elements = container.querySelectorAll('.editor-paragraph');
 65→        const containerRect = container.getBoundingClientRect();
 66→        const result = [];
 67→        let realIndex = 0;
 68→
 69→        elements.forEach((el) => {
 70→            const text = el.textContent.trim();
 71→            if (!text) return;
 72→
 73→            const idx = realIndex;
 74→            el.setAttribute('data-paragraph-index', idx);
 75→            const fingerprint = text.substring(0, 100);
 76→
 77→            const elRect = el.getBoundingClientRect();
 78→            result.push({
 79→                index: idx,
 80→                top: elRect.top - containerRect.top + container.scrollTop,
 81→                height: elRect.height,
 82→                text,
 83→                fingerprint,
 84→            });
 85→
 86→            // Desktop hover listeners (per-paragraph)
 87→            const enter = () => {
 88→                clearLeaveTimer();
 89→                setHoveredIndex(idx);
 90→            };
 91→            const leave = (event) => {
 92→                if (clickedRef.current) return;
 93→
 94→                const nextTarget = event.relatedTarget;
 95→                const layer = layerRef.current;
 96→
 97→                if (nextTarget && layer && layer.contains(nextTarget)) {
 98→                    return;
 99→                }
100→
101→                scheduleLeave(idx);
102→            };
103→            el.addEventListener('mouseenter', enter);
104→            el.addEventListener('mouseleave', leave);
105→            listenersRef.current.push({ el, enter, leave });
106→
107→            realIndex++;
108→        });
109→
110→        setParagraphs(result);
111→    }, [containerRef, clearLeaveTimer, scheduleLeave]);
112→
113→    // Delegated click + touchend handlers on the container
114→    useEffect(() => {
115→        const container = containerRef.current;
116→        if (!container) return;
117→
118→        const handleTouchEnd = (e) => {
119→            const touch = e.changedTouches?.[0];
120→            if (!touch) return;
121→
122→            const target = document.elementFromPoint(touch.clientX, touch.clientY);
123→            const idx = getParagraphIndex(target);
124→            if (idx == null) return;
125→
126→            // Flag so the subsequent synthetic click is ignored
127→            touchHandledRef.current = true;
128→            clearLeaveTimer();
129→            clickedRef.current = true;
130→            setHoveredIndex(idx);
131→            setClickSeq(c => c + 1);
132→        };
133→
134→        const handleClick = (e) => {
135→            // Skip if this click was already handled by touchend
136→            if (touchHandledRef.current) {
137→                touchHandledRef.current = false;
138→                return;
139→            }
140→
141→            const idx = getParagraphIndex(e.target);
142→            if (idx == null) return;
143→
144→            clearLeaveTimer();
145→            clickedRef.current = true;
146→            setHoveredIndex(idx);
147→            setClickSeq(c => c + 1);
148→        };
149→
150→        container.addEventListener('touchend', handleTouchEnd);
151→        container.addEventListener('click', handleClick);
152→
153→        return () => {
154→            container.removeEventListener('touchend', handleTouchEnd);
155→            container.removeEventListener('click', handleClick);
156→        };
157→    }, [containerRef, getParagraphIndex, clearLeaveTimer]);
158→
159→    useEffect(() => {
160→        const container = containerRef.current;
161→        if (!container) return;
162→
163→        const timer = setTimeout(scanParagraphs, 300);
164→
165→        const observer = new MutationObserver((mutations) => {
166→            const layer = layerRef.current;
167→            const isOwnMutation = layer && mutations.every(
168→                (m) => layer.contains(m.target)
169→            );
170→            if (isOwnMutation) return;
171→            scanParagraphs();
172→        });
173→
174→        observer.observe(container, { childList: true, subtree: true, characterData: true });
175→        window.addEventListener('resize', scanParagraphs);
176→
177→        return () => {
178→            clearTimeout(timer);
179→            clearLeaveTimer();
180→            observer.disconnect();
181→            window.removeEventListener('resize', scanParagraphs);
182→            listenersRef.current.forEach(({ el, enter, leave }) => {
183→                el.removeEventListener('mouseenter', enter);
184→                el.removeEventListener('mouseleave', leave);
185→            });
186→            listenersRef.current = [];
187→        };
188→    }, [containerRef, scanParagraphs, clearLeaveTimer]);
189→
190→    // Sync .pcl-active CSS class with hoveredIndex
191→    useEffect(() => {
192→        if (prevActiveElRef.current) {
193→            prevActiveElRef.current.classList.remove('pcl-active');
194→            prevActiveElRef.current = null;
195→        }
196→
197→        if (hoveredIndex == null) {
198→            clickedRef.current = false;
199→            return;
200→        }
201→
202→        const container = containerRef.current;
203→        if (!container) return;
204→
205→        const el = container.querySelector(
206→            `.editor-paragraph[data-paragraph-index="${hoveredIndex}"]`
207→        );
208→        if (el) {
209→            el.classList.add('pcl-active');
210→            prevActiveElRef.current = el;
211→        }
212→    }, [hoveredIndex, containerRef]);
213→
214→    // Dismiss active paragraph when tapping outside content + badge layer
215→    useEffect(() => {
216→        if (!clickedRef.current) return;
217→
218→        const handleOutsideClick = (e) => {
219→            const container = containerRef.current;
220→            const layer = layerRef.current;
221→            if (
222→                (container && container.contains(e.target)) ||
223→                (layer && layer.contains(e.target))
224→            ) return;
225→
226→            clickedRef.current = false;
227→            setHoveredIndex(null);
228→        };
229→
230→        document.addEventListener('click', handleOutsideClick);
231→        return () => document.removeEventListener('click', handleOutsideClick);
232→    }, [hoveredIndex, clickSeq, containerRef]);
233→
234→    const handleBadgeEnter = useCallback((idx) => {
235→        clearLeaveTimer();
236→        setHoveredIndex(idx);
237→    }, [clearLeaveTimer]);
238→
239→    const handleBadgeLeave = useCallback((idx, event) => {
240→        if (clickedRef.current) return;
241→        const nextTarget = event.relatedTarget;
242→        const nextParagraph = nextTarget?.closest?.('.editor-paragraph[data-paragraph-index]');
243→
244→        // Prevent hide jitter when moving directly from badge back to the paragraph.
245→        if (nextParagraph && Number(nextParagraph.getAttribute('data-paragraph-index')) === idx) {
246→            return;
247→        }
248→
249→        scheduleLeave(idx);
250→    }, [scheduleLeave]);
251→
252→    const counts = commentCounts || {};
253→
254→    return (
255→        <div className="pcl-layer" ref={layerRef}>
256→            {paragraphs.map((p) => {
257→                const count = counts[p.index] || 0;
258→                const hasComments = count > 0;
259→                const isVisible = hoveredIndex === p.index || hasComments;
260→
261→                return (
262→                    <div
263→                        key={p.index}
264→                        className={`pcl-badge-anchor ${isVisible ? 'pcl-badge-visible' : ''}`}
265→                        style={{ top: p.top, height: p.height }}
266→                        onMouseEnter={() => handleBadgeEnter(p.index)}
267→                        onMouseLeave={(event) => handleBadgeLeave(p.index, event)}
268→                    >
269→                        <button
270→                            className={`pcl-badge ${hasComments ? 'pcl-badge-active' : ''}`}
271→                            onClick={(e) => {
272→                                e.stopPropagation();
273→                                onParagraphClick({
274→                                    paragraphIndex: p.index,
275→                                    fingerprint: p.fingerprint,
276→                                    text: p.text,
277→                                });
278→                            }}
279→                        >
280→                            <CommentBadge count={count} hasComments={hasComments} />
281→                        </button>
282→                    </div>
283→                );
284→            })}
285→        </div>
286→    );
287→};
288→
289→export default ParagraphCommentLayer;
