293→export const saveProgressService = async (storyId, userId, chapterId, scrollPosition) => {
294→    if (!storyId || !userId || !chapterId) {
295→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
296→    }
297→
298→    // Check if this is a new reader (no existing progress for this user+story)
299→    const { data: existing } = await supabase
300→        .from('reading_progress')
301→        .select('id')
302→        .eq('user_id', userId)
303→        .eq('story_id', storyId)
