 41→// ── Auth middleware (same pattern as routes.js) ──
 42→
 43→const extractBearerToken = (authHeader = "") => {
 44→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 45→    if (!trimmed) return "";
 46→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 47→    if (bearerMatch?.[1]) return bearerMatch[1].trim();
 48→    return trimmed;
 49→};
 50→
 51→const resolveAuthUser = async (token) => {
 52→    if (!token) return { user: null, error: null };
 53→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
 54→    if (authError || !authData?.user?.id) {
 55→        return { user: null, error: authError || new Error("missing user id") };
 56→    }
 57→    return { user: authData.user, error: null };
 58→};
 59→
 60→const requireAuth = async (req, res, next) => {
 61→    const token = extractBearerToken(req.headers?.authorization);
 62→    if (!token) return res.status(401).json({ error: 'not authorized' });
 63→    const { user, error } = await resolveAuthUser(token);
 64→    if (error || !user?.id) return res.status(401).json({ error: 'not authorized' });
 65→    req.userId = user.id;
 66→    req.authUser = user;
 67→    return next();
 68→};
 69→
 70→const optionalAuth = async (req, _res, next) => {
 71→    const token = extractBearerToken(req.headers?.authorization);
 72→    if (!token) return next();
 73→    const { user } = await resolveAuthUser(token);
 74→    if (user?.id) {
 75→        req.userId = user.id;
 76→        req.authUser = user;
 77→    }
 78→    return next();
 79→};
